// Inicializar datos del backup
const staticData = $getWorkflowStaticData('global');
staticData.sqlChunks = [];
staticData.createStatements = {};
staticData.currentTable = null;

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const timestamp = `${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

staticData.timestamp = timestamp;
staticData.filename = `ch_polarizados_backup_${timestamp}.sql`;

return [{ json: { timestamp, filename: staticData.filename } }];

const item = $input.first();
const tableName = item.json['Table'];
const createStatement = item.json['Create Table'];

const staticData = $getWorkflowStaticData('global');
if (!staticData.createStatements) staticData.createStatements = {};
staticData.createStatements[tableName] = createStatement;
staticData.currentTable = tableName;

return [{ json: { tableName, createStatement } }];

const items = $input.all();
const staticData = $getWorkflowStaticData('global');
if (!staticData.sqlChunks) staticData.sqlChunks = [];

const tableName = staticData.currentTable;
const createStatement = staticData.createStatements?.[tableName] || `-- CREATE TABLE ${tableName} no disponible`;

let sql = `\n-- ----------------------------\n-- Tabla: ${tableName}\n-- ----------------------------\n`;
sql += `DROP TABLE IF EXISTS \`${tableName}\`;\n`;
sql += createStatement + ';\n';

if (items.length > 0) {
  sql += `\n-- Datos: ${tableName} (${items.length} filas)\n`;
  for (const item of items) {
    const row = item.json;
    const values = Object.values(row).map(val => {
      if (val === null || val === undefined) return 'NULL';
      if (typeof val === 'number') return String(val);
      if (typeof val === 'boolean') return val ? '1' : '0';
      if (val instanceof Date) return `'${val.toISOString().slice(0,19).replace('T',' ')}'`;
      const str = String(val);
      const escaped = str.replace(/\\/g, '\\\\').replace(/'/g, "\\'")
        .replace(/\r/g, '\\r').replace(/\n/g, '\\n');
      return `'${escaped}'`;
    });
    sql += `INSERT INTO \`${tableName}\` VALUES (${values.join(', ')});\n`;
  }
} else {
  sql += `-- (tabla vacía)\n`;
}

staticData.sqlChunks.push(sql);

return [{ json: { tableName, rowCount: items.length } }];

const staticData = $getWorkflowStaticData('global');

const now = new Date();
const header = [
  `-- ============================================`,
  `-- CH Polarizados - Database Backup`,
  `-- Generado: ${now.toISOString()}`,
  `-- Base de datos: railway (MySQL)`,
  `-- ============================================`,
  ``,
  `SET FOREIGN_KEY_CHECKS=0;`,
  `SET SQL_MODE = 'NO_AUTO_VALUE_ON_ZERO';`,
  `SET NAMES utf8mb4;`,
  ``
].join('\n');

const footer = `\n\nSET FOREIGN_KEY_CHECKS=1;\n-- Fin del backup\n`;

const chunks = staticData.sqlChunks || [];
const fullSQL = header + chunks.join('\n') + footer;
const filename = staticData.filename || `ch_polarizados_backup_${Date.now()}.sql`;
const sizeKB = (Buffer.byteLength(fullSQL, 'utf8') / 1024).toFixed(2);

// Crear archivo binario
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(fullSQL, 'utf8'),
  filename,
  'application/sql'
);

// Limpiar datos estáticos
staticData.sqlChunks = [];
staticData.createStatements = {};
staticData.currentTable = null;

return [{
  json: {
    filename,
    sizeKB,
    timestamp: staticData.timestamp,
    tablesCount: chunks.length
  },
  binary: { data: binaryData }
}];

const input = $input.first().json;
const filename = input.filename || 'backup.sql';
const sizeKB = input.sizeKB || '?';
const tablesCount = input.tablesCount || '?';
const timestamp = input.timestamp || new Date().toISOString();

return [{
  json: {
    message: `✅ *Backup CH Polarizados completado*\n\n📁 Archivo: \`${filename}\`\n📦 Tamaño: ${sizeKB} KB\n🗂 Tablas: ${tablesCount}\n⏰ ${timestamp}\n\n💾 Guardado en Google Drive`
  }
}];

const error = $input.first().json;
const errorMessage = error.error?.message || error.message || 'Error desconocido';
const nodeName = error.error?.node?.name || 'Nodo desconocido';
const timestamp = new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

return [{
  json: {
    message: `❌ *Error en Backup CH Polarizados*\n\n🔴 Nodo: ${nodeName}\n💬 ${errorMessage}\n⏰ ${timestamp}`
  }
}];
